const RTL_LANGS = new Set(["ar"]);  // extend if Hebrew (he) etc. are added later

export function LangProvider({ children }) {
  const [lang, setLang] = useState(
    () => localStorage.getItem("lang") || "en"
  );

  // ✅ Sync document direction whenever lang changes
  useEffect(() => {
    document.documentElement.dir = RTL_LANGS.has(lang) ? "rtl" : "ltr";
    document.documentElement.lang = lang;  // bonus: also sets lang attr for accessibility
  }, [lang]);

  function changeLang(code) {
    setLang(code);
    localStorage.setItem("lang", code);
  }

  function t(key) {
    return (translations[lang] || translations.en)[key]
        ?? translations.en[key]
        ?? key;
  }

  return (
    <LangContext.Provider value={{ t, lang, setLang: changeLang, LANGUAGES }}>
      {children}
    </LangContext.Provider>
  );
}